package com.socialblog.notification.application;import com.socialblog.notification.api.ApiException;import com.socialblog.notification.domain.Notification;import com.socialblog.notification.repository.NotificationRepository;import org.springframework.data.domain.*;import org.springframework.http.HttpStatus;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.time.Instant;import java.util.UUID;
@Service public class NotificationService{public record Response(UUID id,UUID actorId,String type,String entityType,UUID entityId,String metadata,Instant createdAt,Instant readAt){}public record UnreadCount(long count){}private final NotificationRepository notifications;public NotificationService(NotificationRepository n){notifications=n;}@Transactional(readOnly=true)public Page<Response>list(UUID user,Pageable p){return notifications.findByRecipientIdOrderByCreatedAtDesc(user,p).map(this::map);}@Transactional(readOnly=true)public UnreadCount unread(UUID user){return new UnreadCount(notifications.countByRecipientIdAndReadAtIsNull(user));}@Transactional public Response read(UUID id,UUID user){Notification n=notifications.findByIdAndRecipientId(id,user).orElseThrow(()->new ApiException(HttpStatus.NOT_FOUND,"NOTIFICATION_NOT_FOUND","Notification not found"));n.markRead();return map(n);}@Transactional public UnreadCount readAll(UUID user){notifications.markAllRead(user,Instant.now());return unread(user);}private Response map(Notification n){return new Response(n.getId(),n.getActorId(),n.getType().name(),n.getEntityType(),n.getEntityId(),n.getMetadata(),n.getCreatedAt(),n.getReadAt());}}
